    int hi = arr.length;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (x == arr[mid] && (mid == 0 || x != arr[mid-1])) {
            return mid;
        } else if (x <= arr[mid]) {
            hi = mid;
        } else {
            lo = mid + 1;
        }
    }
    return -1;
}

