public static Node reverse_linked_list(Node node) {
    if (node == null) {
        return null;
    }

    Node prev = null;
    Node current = node;
    while (current != null) {
        Node next = current.getSuccessor();
        current.setSuccessor(prev);
        prev = current;
        current = next;
    }
    return prev;
}

public static Node reverse_linked_list(Node node) {
    Node prevnode = null;
    Node nextnode = null;
    while (node != null) {
        nextnode = node.getSuccessor();
        node.setSuccessor(prevnode);
        prevnode = node;
        node = nextnode;
            }
